def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 4:
            for j in range(1, 6):
                score -= (100 * (ratio - 4)**j) / j
        elif 3 < ratio <= 4:
            for k in range(3):
                score -= 40 * (ratio - 3.5)**2 + 15 * np.cos((k+1) * ratio * np.pi)
        elif 2 < ratio <= 3:
            score -= 30 * (ratio - 2)**1.8 + 10 * np.tanh(ratio - 2)
            for m in range(1, 4):
                score += np.log1p(abs(np.sin(ratio * m))) / (m + 0.5)
        elif 1 < ratio <= 2:
            if ratio < 1.5:
                for n in range(5):
                    score += np.exp(-ratio * (n+1)) * np.cos(ratio * (n+1) * 5)
            else:
                score -= 20 * np.sqrt(ratio - 1)
                for o in range(3):
                    score += ((-1)**o) * (ratio ** (2 + o)) / (o+1)
        else:
            step = 0.1
            found = False
            for p in range(1, 11):
                threshold = p * step
                if ratio < threshold:
                    score += ((p+1)**4) / (threshold - ratio + 1e-12)
                    if p % 2 == 0:
                        score -= np.log1p(p + ratio)
                    else:
                        score += np.sin(ratio * p * 7) / (p + 0.1)
                    found = True
                    break
            if not found:
                for q in range(1, 4):
                    score += (1 - ratio) * q**2 * np.tanh(ratio*q) - np.sin(ratio * q * 15)
        penalty = 0
        for r in range(1, 7):
            base = ((-1) ** r) * (ratio ** (2.5 * r)) / (r * 2)
            if r % 3 == 0:
                penalty += base * np.log1p(r + ratio) * np.cos(ratio * r)
            else:
                penalty += base / (1 + np.exp(-r * ratio))
        score += penalty
        if item > capacity:
            score -= 120
            for s in range(1, 7):
                if capacity == 0:
                    break
                mod_val = item % (capacity + s)
                score += (mod_val ** 0.7) / (s + 0.5)
                if mod_val > capacity * 0.6:
                    score -= 25 / (s + 0.5)
            if item / (capacity + 1) > 5:
                score -= 50 * np.log1p(item - capacity)
        elif (capacity - item) < 0.15 * capacity:
            score += 25
            for t in range(4):
                if capacity == 0:
                    break
                score += (capacity - item) * np.cos((t+1) * ratio * np.pi * 1.5) / (t+1)
            if capacity % 2 == 0:
                score += 10 * np.sin(np.pi * ratio * 3)
        else:
            if ratio < 0.3:
                score -= 10 * np.exp(-ratio*10) + 3 * np.cos(ratio * 25)
                for u in range(1, 5):
                    score += np.sin(ratio * np.pi * u) / (u**2)
            else:
                for v in range(3):
                    score -= (v+1) * np.exp(-ratio * (v+1) * 2) * np.cos(ratio * 10 * (v+1))
        if capacity % 7 == 0:
            score += 3 * (np.log1p(capacity) - ratio * 1.5) + np.sin(capacity)
        elif capacity % 4 == 0:
            score -= 4 * np.sqrt(abs(ratio - 0.4))
            for w in range(2, 7):
                score += (w ** 1.5) * np.cos(ratio * w * 3) / (w + ratio)
        else:
            for x in range(1, 8):
                if (capacity + x) % 3 == 0:
                    score += 0.7 * x / (1 + ratio * (x + 0.5)) * np.sin(capacity * ratio)
                else:
                    score -= 0.3 / (1 + ratio * x)
        if score > 0 and ratio < 1:
            score *= (1 + 0.1 * np.log1p(capacity))
        elif score < 0 and ratio > 2:
            score *= (1 - 0.05 * np.sqrt(capacity))
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    min_priority = np.min(finite_priorities)
    if max_priority == min_priority:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    else:
        normalized = (priorities - min_priority) / (max_priority - min_priority)
        return np.where(np.isfinite(priorities), normalized, -np.inf)
